INSERT INTO sports_news (title, summary, content, news_type, league, source, tags, team_names, player_names, is_published, is_verified, publish_time) VALUES
('NBA季后赛最新战报：东西部半决赛激战正酣', '季后赛第二轮进入白热化阶段，各队展开激烈角逐，多场比赛出现精彩绝杀。', '【比赛概述】NBA季后赛第二轮正在如火如荼地进行中。东部方面，凯尔特人展现了强大统治力，凭借出色的防守和团队配合取得领先优势。西部战况更为激烈，掘金队约基奇延续MVP级别表现，场均接近三双数据令人惊叹。', '比赛数据', 'NBA', '篮球训练平台', 'NBA,季后赛,比赛数据', '掘金,凯尔特人,湖人', '约基奇,塔图姆,詹姆斯', 1, 1, NOW()),
('FIBA世界杯预选赛中国队最新动态', '中国男篮积极备战世界杯预选赛，多名年轻球员获得征召，展现全新面貌。', '中国男篮主教练公布了最新一期集训名单，阵容呈现出年轻化趋势。多名在CBA联赛中表现出色的年轻球员获得征召机会，展现了教练组着眼未来的建队思路。新一期国家队在战术上更加现代化，增加了挡拆后的三分出手比重。', '球队动态', 'FIBA', '篮球训练平台', '中国男篮,FIBA,世界杯预选赛', '中国男篮', '', 1, 1, NOW()),
('深度战术解析：掘金约基奇高位策应体系的运作原理', '约基奇的独特打法重新定义了中锋位置，其高位策应体系成为联盟最难防守的战术之一。', '约基奇的高位策应体系是当今NBA最具创造力的进攻体系之一。与传统的低位背筐中锋不同，约基奇大部分时间在罚球线以上区域活动，利用其卓越的传球视野和中投能力组织进攻。穆雷、戈登等球员持续空切篮下，手递手传球是一大杀招。', '战术分析', 'NBA', '篮球训练平台', '战术分析,约基奇,掘金,高位策应', '丹佛掘金', '约基奇,穆雷,戈登', 1, 1, DATE_SUB(NOW(), INTERVAL 6 HOUR)),
('奥运会篮球赛事前瞻：各强队阵容分析与夺冠预测', '巴黎奥运会篮球赛事临近，美国、法国、西班牙、加拿大等强队纷纷公布豪华阵容。', '奥运会篮球赛事即将拉开帷幕。美国男篮虽然缺少部分巨星但依然星光熠熠；法国坐拥东道主之利，戈贝尔+文班亚马的内线组合堪称顶级；加拿大队NBA球员数量仅次于美国。FIBA规则对比赛影响显著：无防守三秒有利于区域联防。', '比赛数据', '奥运会', '篮球训练平台', '奥运会,篮球,美国队,法国队', '美国队,法国队,加拿大队', '文班亚马,戈贝尔', 1, 1, DATE_SUB(NOW(), INTERVAL 12 HOUR)),
('球员技术分析：新一代控球后卫的技术进化趋势', '现代控球后卫的技术特点发生了根本性变化，得分能力成为衡量顶级控卫的核心指标。', '篮球运动中控球后卫这一位置在过去20年经历了最剧烈的变革。从传统的"传球第一"组织型后卫，到今天集得分、组织、防守于一体的全能型后卫，技术要求的演变反映了篮球运动的整体发展趋势。青少年培养应注意三分投射是第一优先级技能。', '球员表现', 'NBA', '篮球训练平台', '技术分析,控球后卫,库里,东契奇', '多支球队', '库里,东契奇,利拉德', 1, 1, DATE_SUB(NOW(), INTERVAL 18 HOUR)),
('欧洲篮球锦标赛综述：各国联赛与青训体系对比', '欧洲篮球近年来的进步源于完善的青训体系，各国联赛和青训模式值得深入研究。', '欧洲篮球的国际竞争力在过去十年大幅提升，越来越多的欧洲球员在NBA取得核心位置。西班牙ACB联赛作为欧洲第一联赛，U12-U18完整梯队体系成熟；法国近年青训产出爆炸式增长，文班亚马现象即源于此。', '球队动态', '欧洲杯', '篮球训练平台', '欧洲篮球,青训体系,西班牙,法国', '西班牙,法国,塞尔维亚', '文班亚马,约基奇', 1, 1, DATE_SUB(NOW(), INTERVAL 1 DAY));
